-- staff hire_date

DELIMITER $$
CREATE TRIGGER trg_staff_hire_date
BEFORE INSERT ON staff
FOR EACH ROW
BEGIN
    IF NEW.hire_date > CURDATE() THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'Hire date cannot be in the future';
    END IF;
END$$
