BEFORE UPDATE ON med_proc
FOR EACH ROW
BEGIN
    DECLARE v_hosp_patient_id INT UNSIGNED;
    DECLARE v_hosp_admission  DATETIME;
    DECLARE v_hosp_discharge  DATETIME;

